using Libdl

# ─── Determine source directory ────────────────────────────────────────────────
const TYPEDB_DRIVER_SRC = get(ENV, "TYPEDB_DRIVER_SRC", "")

if isempty(TYPEDB_DRIVER_SRC)
    @warn """
    TYPEDB_DRIVER_SRC not set.
    Set this environment variable to the path of a cloned typedb-driver repository, e.g.:
        export TYPEDB_DRIVER_SRC=/path/to/typedb-driver
    Skipping automatic build. If you have a pre-built library, set TYPEDB_DRIVER_LIB
    to the absolute path of libtypedb_driver_clib.<ext>.
    """
end

# ─── Determine library file name by platform ───────────────────────────────────
const LIB_NAME = if Sys.isapple()
    "libtypedb_driver_clib.dylib"
elseif Sys.islinux()
    "libtypedb_driver_clib.so"
elseif Sys.iswindows()
    "typedb_driver_clib.dll"
else
    error("Unsupported platform: $(Sys.MACHINE)")
end

# ─── Derive output directory ────────────────────────────────────────────────────
const DEPS_DIR    = @__DIR__
const LIB_DIR     = joinpath(DEPS_DIR, "usr", "lib")
const DEPS_FILE   = joinpath(DEPS_DIR, "deps.jl")

mkpath(LIB_DIR)

# ─── Build from source if TYPEDB_DRIVER_SRC is set ─────────────────────────────
function build_from_source(src_root::String)
    c_manifest = joinpath(src_root, "c", "Cargo.toml")
    isfile(c_manifest) ||
        error("Cannot find $(c_manifest). Is TYPEDB_DRIVER_SRC pointing to the root of the typedb-driver repo?")

    @info "Building typedb_driver_clib via cargo (this may take a few minutes)…"
    cmd = `cargo build --manifest-path $(c_manifest) --release`
    run(cmd)

    # Cargo puts the artifact in target/release relative to the workspace root
    # The workspace Cargo.toml is at <src_root>/Cargo.toml; target/ is adjacent
    target_dir = joinpath(src_root, "target", "release")
    src_lib = joinpath(target_dir, LIB_NAME)
    isfile(src_lib) ||
        error("Built library not found at $(src_lib). Check cargo output above.")

    dst_lib = joinpath(LIB_DIR, LIB_NAME)
    cp(src_lib, dst_lib; force=true)
    @info "Copied $(LIB_NAME) → $(dst_lib)"
    return dst_lib
end

# ─── Resolve library path ───────────────────────────────────────────────────────
lib_path = let
    # 1. Explicit override via environment
    override = get(ENV, "TYPEDB_DRIVER_LIB", "")
    if !isempty(override)
        abspath(override)
    # 2. Already copied into deps/usr/lib (e.g., from a previous build)
    elseif isfile(joinpath(LIB_DIR, LIB_NAME))
        joinpath(LIB_DIR, LIB_NAME)
    # 3. Build from source
    elseif !isempty(TYPEDB_DRIVER_SRC)
        build_from_source(TYPEDB_DRIVER_SRC)
    else
        # Fall back to a placeholder so the package at least loads without error
        joinpath(LIB_DIR, LIB_NAME)
    end
end

# ─── Write deps.jl ─────────────────────────────────────────────────────────────
open(DEPS_FILE, "w") do io
    println(io, "# This file is generated by deps/build.jl – do not edit manually.")
    println(io, "")
    println(io, "import Libdl")
    println(io, "")
    println(io, "const libtypedb = " * repr(lib_path))
    println(io, "")
    println(io, "function check_deps()")
    println(io, "    isfile(libtypedb) || error(")
    println(io, "        \"TypeDB driver library not found at \\\"\" * libtypedb * \"\\\".\\n\" *")
    println(io, "        \"Run `Pkg.build(\\\"TypeDBClient\\\")` after setting \" *")
    println(io, "        \"TYPEDB_DRIVER_SRC or TYPEDB_DRIVER_LIB.\")")
    println(io, "    Libdl.dlopen(libtypedb)")
    println(io, "end")
end

@info "deps.jl written → library path: $(lib_path)"
